sys_script.script:
(function executeRule(current, previous) {

    try {

        // Move to Running
        current.setValue("status", "Running");
        current.setValue("started_at", new GlideDateTime());
        current.update();

        var runId = current.getUniqueValue();

        /* =========================
           1️⃣ VALIDATION
        ========================= */

        var validator = new IncentNowValidationEngine();
        var validationResult = validator.validateRun(runId);

        if (!validationResult || validationResult.valid == 0) {

            current.setValue("status", "Failed");
            current.setValue("completed_at", new GlideDateTime());
            current.update();
            return;
        }

        /* =========================
           2️⃣ DRY RUN CHECK
        ========================= */

        if (current.getValue("is_dry_run") == "true") {

            current.setValue("status", "Completed");
            current.setValue("completed_at", new GlideDateTime());
            current.update();
            return;
        }

        /* =========================
           3️⃣ TRANSFORM
        ========================= */

        var engine = new IncentNowTransformEngine();
        engine.execute(runId);

        /* =========================
           4️⃣ COMPLETE
        ========================= */

        current.setValue("status", "Completed");
        current.setValue("completed_at", new GlideDateTime());
        current.update();

    } catch (ex) {

        current.setValue("status", "Failed");
        current.setValue("completed_at", new GlideDateTime());
        current.update();

        gs.error("Ingestion execution failed: " + ex);
    }

})(current, previous);
